package store

import (
	"context"
	"time"
)

type SessionInfo struct {
	SessionID      string            `json:"session_id"`
	UserID         string            `json:"user_id"`
	Kind           string            `json:"kind"`
	PodName        string            `json:"pod_name"`
	PodNamespace   string            `json:"pod_namespace"`
	Endpoint       string            `json:"endpoint"`
	Status         string            `json:"status"`
	CreatedAt      time.Time         `json:"created_at"`
	LastActivityAt time.Time         `json:"last_activity_at"`
	ExpiresAt      time.Time         `json:"expires_at"`
	Metadata       map[string]string `json:"metadata"`
}

type Store interface {
	Set(ctx context.Context, session *SessionInfo) error
	Get(ctx context.Context, sessionID string) (*SessionInfo, error)
	Delete(ctx context.Context, sessionID string) error
	UpdateLastActivity(ctx context.Context, sessionID string) error
	GetExpiredSessions(ctx context.Context, threshold time.Time) ([]string, error)
	Close() error
	Ping(ctx context.Context) error
}

type Options struct {
	StoreType   string
	RedisAddr   string
	RedisPassword string
	ValkeyAddr  string
	ValkeyPassword string
}

func NewStore(opts Options) (Store, error) {
	switch opts.StoreType {
	case "redis":
		return NewRedisStore(opts.RedisAddr, opts.RedisPassword)
	case "valkey":
		return NewValkeyStore(opts.ValkeyAddr, opts.ValkeyPassword)
	default:
		return NewRedisStore(opts.RedisAddr, opts.RedisPassword)
	}
}

package store

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/go-redis/redis/v8"
)

type RedisStore struct {
	client     *redis.Client
	expiryKey  string
	activityKey string
}

func NewRedisStore(addr, password string) (*RedisStore, error) {
	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to redis: %w", err)
	}

	return &RedisStore{
		client:      client,
		expiryKey:   "session:expiry",
		activityKey: "session:last_activity",
	}, nil
}

func (s *RedisStore) sessionKey(sessionID string) string {
	return fmt.Sprintf("session:%s", sessionID)
}

func (s *RedisStore) Set(ctx context.Context, session *SessionInfo) error {
	data, err := json.Marshal(session)
	if err != nil {
		return ErrSerializationFailed
	}

	pipe := s.client.Pipeline()

	pipe.Set(ctx, s.sessionKey(session.SessionID), data, session.ExpiresAt.Sub(time.Now()))

	pipe.ZAdd(ctx, s.expiryKey, &redis.Z{
		Score:  float64(session.ExpiresAt.Unix()),
		Member: session.SessionID,
	})

	pipe.ZAdd(ctx, s.activityKey, &redis.Z{
		Score:  float64(session.LastActivityAt.Unix()),
		Member: session.SessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to set session: %w", err)
	}

	return nil
}

func (s *RedisStore) Get(ctx context.Context, sessionID string) (*SessionInfo, error) {
	data, err := s.client.Get(ctx, s.sessionKey(sessionID)).Bytes()
	if err == redis.Nil {
		return nil, ErrSessionNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("failed to get session: %w", err)
	}

	var session SessionInfo
	if err := json.Unmarshal(data, &session); err != nil {
		return nil, ErrSerializationFailed
	}

	return &session, nil
}

func (s *RedisStore) Delete(ctx context.Context, sessionID string) error {
	pipe := s.client.Pipeline()

	pipe.Del(ctx, s.sessionKey(sessionID))
	pipe.ZRem(ctx, s.expiryKey, sessionID)
	pipe.ZRem(ctx, s.activityKey, sessionID)

	_, err := pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to delete session: %w", err)
	}

	return nil
}

func (s *RedisStore) UpdateLastActivity(ctx context.Context, sessionID string) error {
	session, err := s.Get(ctx, sessionID)
	if err != nil {
		return err
	}

	session.LastActivityAt = time.Now()

	data, err := json.Marshal(session)
	if err != nil {
		return ErrSerializationFailed
	}

	pipe := s.client.Pipeline()

	pipe.Set(ctx, s.sessionKey(sessionID), data, session.ExpiresAt.Sub(time.Now()))
	pipe.ZAdd(ctx, s.activityKey, &redis.Z{
		Score:  float64(session.LastActivityAt.Unix()),
		Member: sessionID,
	})

	_, err = pipe.Exec(ctx)
	if err != nil {
		return fmt.Errorf("failed to update last activity: %w", err)
	}

	return nil
}

func (s *RedisStore) GetExpiredSessions(ctx context.Context, threshold time.Time) ([]string, error) {
	result, err := s.client.ZRangeByScore(ctx, s.expiryKey, &redis.ZRangeBy{
		Min: "0",
		Max: fmt.Sprintf("%d", threshold.Unix()),
	}).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to get expired sessions: %w", err)
	}

	return result, nil
}

func (s *RedisStore) Close() error {
	return s.client.Close()
}

func (s *RedisStore) Ping(ctx context.Context) error {
	return s.client.Ping(ctx).Err()
}

