package main

import (
	"flag"
	"log"
	"os"

	"github.com/agentcube/agentcube/pkg/picod"
)

func main() {
	port := flag.String("port", "8080", "Port to listen on")
	workspace := flag.String("workspace", "/workspace", "Workspace directory for code execution")
	jwtSecret := flag.String("jwt-secret", "", "JWT secret for authentication")
	flag.Parse()

	if port == nil || *port == "" {
		log.Fatal("port is required")
	}
	if workspace == nil || *workspace == "" {
		log.Fatal("workspace is required")
	}

	envPort := os.Getenv("PORT")
	if envPort != "" {
		port = &envPort
	}

	envWorkspace := os.Getenv("WORKSPACE")
	if envWorkspace != "" {
		workspace = &envWorkspace
	}

	envJWTSecret := os.Getenv("JWT_SECRET")
	if envJWTSecret != "" {
		jwtSecret = &envJWTSecret
	}

	cfg := picod.Config{
		Port:      *port,
		Workspace: *workspace,
		JWTSecret: *jwtSecret,
	}

	server := picod.NewServer(cfg)
	if err := server.Start(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}

package picod

import (
	"fmt"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/gin-gonic/gin"
)

type Config struct {
	Port      string
	Workspace string
	JWTSecret string
}

type Server struct {
	config    Config
	router    *gin.Engine
	server    *http.Server
}

func NewServer(cfg Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()
	router.Use(gin.Recovery())
	router.Use(gin.Logger())

	server := &Server{
		config: cfg,
		router: router,
	}

	server.setupRoutes()

	return server
}

func (s *Server) setupRoutes() {
	s.router.GET("/health", s.handleHealth)

	api := s.router.Group("/api")
	if s.config.JWTSecret != "" {
		api.Use(s.authMiddleware())
	}
	api.POST("/execute", s.handleExecute)
	api.POST("/files", s.handleFileUpload)
	api.GET("/files", s.handleFileList)
	api.GET("/files/*path", s.handleFileDownload)
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status": "healthy",
		"time":   time.Now().Format(time.RFC3339),
	})
}

func (s *Server) handleExecute(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body"})
		return
	}

	if req.Command == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "command is required"})
		return
	}

	result, err := s.runCommand(c.Request.Context(), req.Command, req.Args, req.Env, req.Timeout)
	if err != nil {
		if err == ErrProcessKilled {
			c.JSON(http.StatusInternalServerError, gin.H{
				"error":       "process was killed due to resource limits",
				"oom":         true,
				"stdout":      result.Stdout,
				"stderr":      result.Stderr,
				"exit_code":   result.ExitCode,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":     err.Error(),
			"stdout":    result.Stdout,
			"stderr":    result.Stderr,
			"exit_code": result.ExitCode,
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"stdout":    result.Stdout,
		"stderr":    result.Stderr,
		"exit_code": result.ExitCode,
	})
}

func (s *Server) handleFileUpload(c *gin.Context) {
	file, header, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "file is required"})
		return
	}
	defer file.Close()

	filename := c.PostForm("filename")
	if filename == "" {
		filename = header.Filename
	}

	sanitizedPath := s.sanitizePath(filename)
	destPath := filepath.Join(s.config.Workspace, sanitizedPath)

	if err := os.MkdirAll(filepath.Dir(destPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create directory"})
		return
	}

	dest, err := os.Create(destPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create file"})
		return
	}
	defer dest.Close()

	if _, err := dest.ReadFrom(file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to write file"})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"filename": sanitizedPath,
		"size":     header.Size,
	})
}

func (s *Server) handleFileList(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		path = "."
	}

	sanitizedPath := s.sanitizePath(path)
	dirPath := filepath.Join(s.config.Workspace, sanitizedPath)

	entries, err := os.ReadDir(dirPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to read directory"})
		return
	}

	var files []FileInfo
	for _, entry := range entries {
		info, _ := entry.Info()
		files = append(files, FileInfo{
			Name:    entry.Name(),
			IsDir:   entry.IsDir(),
			Size:    info.Size(),
			ModTime: info.ModTime().Format(time.RFC3339),
		})
	}

	c.JSON(http.StatusOK, gin.H{"files": files})
}

func (s *Server) handleFileDownload(c *gin.Context) {
	path := c.Param("path")
	sanitizedPath := s.sanitizePath(path)
	filePath := filepath.Join(s.config.Workspace, sanitizedPath)

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", filepath.Base(filePath)))
	c.Header("Content-Type", "application/octet-stream")
	c.File(filePath)
}

func (s *Server) sanitizePath(path string) string {
	clean := filepath.Clean(path)
	if filepath.IsAbs(clean) {
		return ""
	}
	if clean == ".." || len(clean) > 2 && clean[:3] == ".." {
		return ""
	}
	return clean
}

func (s *Server) Start() error {
	s.server = &http.Server{
		Addr:    ":" + s.config.Port,
		Handler: s.router,
	}

	log.Printf("PicoD starting on port %s", s.config.Port)
	return s.server.ListenAndServe()
}

func (s *Server) Stop() error {
	if s.server != nil {
		return s.server.Shutdown(nil)
	}
	return nil
}

package picod

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"os/exec"
	"sync"
	"syscall"
	"time"
)

var (
	ErrProcessKilled = fmt.Errorf("process was killed")
	ErrTimeout      = fmt.Errorf("command timed out")
)

type ExecuteRequest struct {
	Command string            `json:"command"`
	Args    []string          `json:"args,omitempty"`
	Env     map[string]string `json:"env,omitempty"`
	Timeout int               `json:"timeout,omitempty"`
}

type ExecuteResult struct {
	Stdout   string
	Stderr   string
	ExitCode int
}

type FileInfo struct {
	Name    string `json:"name"`
	IsDir   bool   `json:"is_dir"`
	Size    int64  `json:"size"`
	ModTime string `json:"mod_time"`
}

func (s *Server) runCommand(ctx context.Context, command string, args []string, env map[string]string, timeout int) (*ExecuteResult, error) {
	if timeout <= 0 {
		timeout = 60
	}

	cmd := exec.CommandContext(ctx, command, args...)
	cmd.Dir = s.config.Workspace

	cmd.Env = os.Environ()
	for k, v := range env {
		cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	resourceLimit := &syscall.Rlimit{
		Cur: 128 * 1024 * 1024,
		Max: 256 * 1024 * 1024,
	}
	syscall.Setrlimit(syscall.RLIMIT_AS, resourceLimit)

	err := cmd.Start()
	if err != nil {
		return nil, err
	}

	done := make(chan error, 1)
	go func() {
		done <- cmd.Wait()
	}()

	select {
	case <-ctx.Done():
		cmd.Process.Kill()
		return nil, ctx.Err()
	case err := <-done:
		if err != nil {
			if exitErr, ok := err.(*exec.ExitError); ok {
				if status, ok := exitErr.Sys().(syscall.WaitStatus); ok {
					return &ExecuteResult{
						Stdout:   stdout.String(),
						Stderr:   stderr.String(),
						ExitCode: status.ExitStatus(),
					}, nil
				}
			}
			return nil, err
		}
		return &ExecuteResult{
			Stdout:   stdout.String(),
			Stderr:   stderr.String(),
			ExitCode: 0,
		}, nil
	case <-time.After(time.Duration(timeout) * time.Second):
		cmd.Process.Kill()
		return &ExecuteResult{
			Stdout:   stdout.String(),
			Stderr:   stderr.String() + "\nCommand timed out",
			ExitCode: -1,
		}, ErrTimeout
	}
}

type OutputBuffer struct {
	mu       sync.Mutex
	data     bytes.Buffer
	chunkSize int
}

func NewOutputBuffer(chunkSize int) *OutputBuffer {
	if chunkSize <= 0 {
		chunkSize = 64 * 1024
	}
	return &OutputBuffer{
		chunkSize: chunkSize,
	}
}

func (ob *OutputBuffer) Write(p []byte) (n int, err error) {
	ob.mu.Lock()
	defer ob.mu.Unlock()

	if ob.data.Len() > ob.chunkSize {
		return 0, fmt.Errorf("output exceeds buffer limit of %d bytes", ob.chunkSize)
	}

	return ob.data.Write(p)
}

func (ob *OutputBuffer) String() string {
	ob.mu.Lock()
	defer ob.mu.Unlock()
	return ob.data.String()
}

package picod

import (
	"net/http"
	"strings"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header format"})
			return
		}

		tokenString := parts[1]

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
				return nil, jwt.ErrSignatureInvalid
			}
			return []byte(s.config.JWTSecret), nil
		})

		if err != nil || !token.Valid {
			if err == jwt.ErrTokenExpired {
				c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "token expired"})
				return
			}
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		claims, ok := token.Claims.(jwt.MapClaims)
		if !ok {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token claims"})
			return
		}

		c.Set("claims", claims)
		c.Next()
	}
}

