package main

import (
	"context"
	"flag"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/agentcube/agentcube/pkg/store"
	"github.com/agentcube/agentcube/pkg/workload"
)

func main() {
	port := flag.String("port", "8080", "Port to listen on")
	storeType := flag.String("store", "redis", "Store type (redis/valkey)")
	redisAddr := flag.String("redis-addr", "localhost:6379", "Redis address")
	redisPassword := flag.String("redis-password", "", "Redis password")
	namespace := flag.String("namespace", "agentcube", "Kubernetes namespace")
	jwtSecret := flag.String("jwt-secret", "", "JWT secret for token validation")
	flag.Parse()

	storeOpts := store.Options{
		StoreType:    *storeType,
		RedisAddr:    *redisAddr,
		RedisPassword: *redisPassword,
	}

	sessionStore, err := store.NewStore(storeOpts)
	if err != nil {
		log.Fatalf("Failed to create store: %v", err)
	}
	defer sessionStore.Close()

	wm := workload.NewManager(sessionStore, workload.Config{
		Namespace: *namespace,
		JWTSecret: *jwtSecret,
	})

	router := workload.NewRouter(wm)

	srv := &http.Server{
		Addr:    ":" + *port,
		Handler: router,
	}

	go func() {
		log.Printf("Workload Manager starting on port %s", *port)
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("Server failed: %v", err)
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	log.Println("Shutting down server...")
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := srv.Shutdown(ctx); err != nil {
		log.Fatalf("Server forced to shutdown: %v", err)
	}

	log.Println("Server exited")
}

package workload

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/agentcube/agentcube/pkg/store"
	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
)

type Manager struct {
	store     store.Store
	clientset *kubernetes.Clientset
	config    Config
	gc        *GarbageCollector
}

type Config struct {
	Namespace string
	JWTSecret string
}

func NewManager(sessionStore store.Store, cfg Config) *Manager {
	config, err := rest.InClusterConfig()
	if err != nil {
		log.Printf("Using mock clientset (not in cluster): %v", err)
	}

	var clientset *kubernetes.Clientset
	if err == nil {
		clientset, err = kubernetes.NewForConfig(config)
		if err != nil {
			log.Printf("Failed to create clientset: %v", err)
		}
	}

	mgr := &Manager{
		store:     sessionStore,
		clientset: clientset,
		config:    cfg,
	}

	mgr.gc = NewGarbageCollector(sessionStore, clientset, cfg.Namespace)
	go mgr.gc.Start()

	return mgr
}

type CreateSessionRequest struct {
	Kind    string `json:"kind"`
	UserID  string `json:"user_id"`
	Image   string `json:"image,omitempty"`
	Timeout int    `json:"timeout,omitempty"`
}

type CreateSessionResponse struct {
	SessionID string `json:"session_id"`
	Endpoint  string `json:"endpoint"`
	PodName   string `json:"pod_name"`
	PodNamespace string `json:"pod_namespace"`
}

func (m *Manager) CreateSandbox(c *gin.Context) {
	var req CreateSessionRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body"})
		return
	}

	if req.Kind == "" {
		req.Kind = "agent-runtime"
	}
	if req.Timeout <= 0 {
		req.Timeout = 3600
	}

	sessionID := uuid.New().String()
	podName := fmt.Sprintf("agent-%s", sessionID[:8])

	existingSession, err := m.store.Get(c.Request.Context(), sessionID)
	if err == nil && existingSession != nil {
		c.JSON(http.StatusConflict, gin.H{
			"error":       "session already exists",
			"session_id":  existingSession.SessionID,
			"endpoint":    existingSession.Endpoint,
		})
		return
	}

	if m.clientset != nil {
		pod := &corev1.Pod{
			ObjectMeta: metav1.ObjectMeta{
				Name:      podName,
				Namespace: m.config.Namespace,
				Labels: map[string]string{
					"agentcube.runtime": req.Kind,
					"agentcube.session": sessionID,
				},
			},
			Spec: corev1.PodSpec{
				Containers: []corev1.Container{
					{
						Name:  "agent",
						Image: req.Image,
					},
				},
			},
		}

		_, err := m.clientset.CoreV1().Pods(m.config.Namespace).Create(c.Request.Context(), pod, metav1.CreateOptions{})
		if err != nil {
			log.Printf("Failed to create pod: %v", err)
		}
	}

	session := &store.SessionInfo{
		SessionID:      sessionID,
		UserID:         req.UserID,
		Kind:           req.Kind,
		PodName:        podName,
		PodNamespace:   m.config.Namespace,
		Endpoint:       fmt.Sprintf("http://%s.%s.svc.cluster.local:8080", podName, m.config.Namespace),
		Status:         "Creating",
		CreatedAt:      time.Now(),
		LastActivityAt: time.Now(),
		ExpiresAt:      time.Now().Add(time.Duration(req.Timeout) * time.Second),
		Metadata:       map[string]string{},
	}

	if err := m.store.Set(c.Request.Context(), session); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create session"})
		return
	}

	go m.waitForPodRunning(c.Request.Context(), sessionID, podName)

	c.JSON(http.StatusCreated, CreateSessionResponse{
		SessionID:    sessionID,
		Endpoint:     session.Endpoint,
		PodName:      podName,
		PodNamespace: m.config.Namespace,
	})
}

func (m *Manager) waitForPodRunning(ctx context.Context, sessionID, podName string) {
	if m.clientset == nil {
		return
	}

	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		select {
		case <-ctx.Done():
			return
		default:
		}

		pod, err := m.clientset.CoreV1().Pods(m.config.Namespace).Get(ctx, podName, metav1.GetOptions{})
		if err != nil {
			continue
		}

		if pod.Status.Phase == corev1.PodRunning {
			session, err := m.store.Get(ctx, sessionID)
			if err == nil && session != nil {
				session.Status = "Running"
				session.Endpoint = fmt.Sprintf("http://%s.%s.svc.cluster.local:8080", podName, m.config.Namespace)
				m.store.Set(ctx, session)
			}
			return
		}

		if pod.Status.Phase == corev1.PodFailed {
			session, err := m.store.Get(ctx, sessionID)
			if err == nil && session != nil {
				session.Status = "Failed"
				m.store.Set(ctx, session)
			}
			return
		}
	}
}

func (m *Manager) DeleteSession(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "session_id is required"})
		return
	}

	session, err := m.store.Get(c.Request.Context(), sessionID)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "session not found"})
		return
	}

	if m.clientset != nil && session.PodName != "" {
		err := m.clientset.CoreV1().Pods(m.config.Namespace).Delete(c.Request.Context(), session.PodName, metav1.DeleteOptions{})
		if err != nil {
			log.Printf("Failed to delete pod: %v", err)
		}
	}

	if err := m.store.Delete(c.Request.Context(), sessionID); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to delete session"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "session deleted"})
}

func (m *Manager) GetSession(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "session_id is required"})
		return
	}

	session, err := m.store.Get(c.Request.Context(), sessionID)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "session not found"})
		return
	}

	c.JSON(http.StatusOK, session)
}

func (m *Manager) Health(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}
